import { readdir, readFile, writeFile } from 'fs/promises';
import { join, extname } from 'path';

const APP_DIR = join\(
  'C:\\\\Users\\\\konia\\\\OneDrive - Stichting Hogeschool Utrecht\\\\hulpmetit-nextgen',
  'app'
\);

// Recursively find all .tsx files
async function findTsxFiles\(dir\) {
  const entries = await readdir\(dir, { withFileTypes: true }\);
  const files = [];
  for \(const entry of entries\) {
    const fullPath = join\(dir, entry.name\);
    if \(entry.isDirectory\(\)\) {
      files.push\(...\(await findTsxFiles\(fullPath\)\)\);
    } else if \(extname\(entry.name\) === '.tsx'\) {
      files.push\(fullPath\);
    }
  }
  return files;
}

async function main\(\) {
  const tsxFiles = await findTsxFiles\(APP_DIR\);
  console.log\(`Found ${tsxFiles.length} .tsx files in app/ directory.\\n`\);

  const patterns = [
    { search: /08:00 tot 22:00/g, replace: '08:00 tot 21:00' },
    { search: /09:00 tot 21:00/g, replace: '08:00 tot 21:00' },
  ];

  const modifiedFiles = [];

  for \(const filePath of tsxFiles\) {
    const original = await readFile\(filePath, 'utf-8'\);
    let content = original;

    for \(const { search, replace } of patterns\) {
      content = content.replace\(search, replace\);
    }

    if \(content !== original\) {
      await writeFile\(filePath, content, 'utf-8'\);
      // Make path relative for cleaner output
      const relative = filePath.replace\(APP_DIR.replace\(/app$/, ''\), ''\);
      modifiedFiles.push\(relative\);
    }
  }

  console.log\(`Modified ${modifiedFiles.length} file\(s\):\\n`\);
  for \(const f of modifiedFiles\) {
    console.log\(`  - ${f}`\);
  }
}

main\(\).catch\(\(err\) => {
  console.error\('Error:', err\);
  process.exit\(1\);
}\);
SCRIPT_EOF)

